var e=JSON.parse(`[{"id":"L1_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"저어......","JPN":"あの……","ENG":"Erm...","TWN":"請問……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"로자리아 님은 어디로 가셨죠?","JPN":"ロザリアさんはどこに行ったんですか？","ENG":"Where's Lady Rosaria?","TWN":"羅莎莉亞大人去哪裡了？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"오너께선 지금쯤 호텔에 체크인을 하셨을 겁니다.","JPN":"ご主人様は今頃ホテルにチェックインされたはずです。","ENG":"She must have checked in to a hotel by now.","TWN":"這個時候主人應該已經住進飯店裡了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"워낙 움직이길 싫어하는 분이라서 말이죠.","JPN":"体を動かすことが大嫌いな方ですので。","ENG":"She doesn't like to move around too much.","TWN":"她是一位非常懶得動的人。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"의뢰인 분께선 잠시 저희와 함께 동행만 해주시면 됩니다.","JPN":"依頼人のあなたは、しばらく私と同行していただければ結構です。","ENG":"All you have to do is come with us.","TWN":"委託人小姐只要與我們同行就可以了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"모든 일은 예정대로 아주 잘 풀릴 거에요.","JPN":"すべてのことは、予定通りすんなり解決できると思います。","ENG":"We'll take care of everything else.","TWN":"所有事情都在預料之中，會進行得很順利的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"해변에 간다고 해서 왔더니, 여긴 아무 것도 없는데요?","JPN":"海辺に行くと言われて来たんですが、ここには何もありませんね。","ENG":"You said we were going to a beach, but there's nothing here.","TWN":"我們不是說要去海邊嗎，可是這裡什麼也沒有呀？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"사람도 한 명 안 보이고......","JPN":"誰もいませんし……","ENG":"No one else, either.","TWN":"一個人也沒有……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"운명의 상대를 찾는 것은 쉽지 않습니다.","JPN":"運命の相手を探すことはそうそう簡単ではありません。","ENG":"It's not easy to find your soul mate.","TWN":"命運之人不是那麼容易找到的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"대상을 특정할 수 없기 때문에 평범한 방법은 통하지 않지요.","JPN":"対象を特定できませんので、普通の方法は通じませんよ。","ENG":"Because we can't specify them, we can't use ordinary methods.","TWN":"我們現在無法鎖定對象，所以普通的方式是行不通的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"하지만 그럴 때를 위해, 저희 폴른 호크 탐정 사무소에는 <color=#83dcb7>특별한 마법</color>이 준비되어 있습니다.","JPN":"しかし、そんなときのために、私たちフォーレン・ホーク探偵事務所は<color=#83dcb7>特別な魔法</color>を用意しております。","ENG":"But Fallen Hawk Private Eye has <color=#83dcb7>special magic</color> to use at times like this.","TWN":"不過為了這種時候，我們墮落之鷹偵探事務所準備了<color=#83dcb7>特別的魔法</color>。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"......마법? 지금 바닥에 그리고 있는 게 혹시 그건가요? 마법진?","JPN":"……魔法？　今、床に描いているのって、もしかしてあれですか？　魔法陣？","ENG":"Magic? That thing you're drawing on the ground. Is that a pentacle?","TWN":"……魔法？就是你在地上畫的那個嗎？魔法陣？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 이건 그냥 기분을 내기 위한 겁니다.","JPN":"あ、これはただ雰囲気を出すためのものです。","ENG":"Ah, no. This is just to set the mood.","TWN":"不不，這只是為了營造氣氛。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님께서 이런 걸 좋아하시거든요. 너무 신경 쓰지 마시길.","JPN":"ご主人様はこういうものが好きなんです。あまり気にしないでください。","ENG":"My mistress likes this sort of thing. Please pay no mind.","TWN":"主人喜歡弄這些東西，請您別介意。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"우선은 <color=#83dcb7>마법</color>을 위한 재료를 모으는 게 우선이겠죠.","JPN":"とりあえず<color=#83dcb7>魔法</color>のための材料集めから始めましょう。","ENG":"First, we should gather the ingredients for the <color=#83dcb7>magic</color>.","TWN":"首先，我們要收集<color=#83dcb7>魔法</color>材料。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그리고 이 근처엔 살아있는 유용한 재료들이 아주 많이 있거든요.","JPN":"この辺りには生きてる有用な材料がたくさんあります。","ENG":"There are many useful live ingredients around here.","TWN":"這附近有很多活生生的有用材料。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"살아있는...... 유용한 재료?","JPN":"生きてる……有用な材料？","ENG":"Useful... live ingredients?","TWN":"活生生的……有用材料？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"들었어? 슬슬 냄새를 맡고 오는 거 같은데?","JPN":"聞いたか？　そろそろ匂いを嗅ぎつけてきたみたいだけど？","ENG":"Hear that? Looks like they've caught a whiff of them.","TWN":"聽到了嗎？它們好像聞到氣味過來了？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"응......? 방금 그 소린 설마...... 침식체?","JPN":"うん……？　今の音ってまさか……侵食体？","ENG":"Huh? That sound... Oh no, C.O.s?","TWN":"嗯……？剛剛那個聲音該不會是……侵蝕體？"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"네, 이면세계에서 갓 캐온 신선한 이터니움 원석을 여기저기 뿌려뒀거든요.","JPN":"はい、裏世界から掘り出したばかりの新鮮なエタニウムの原石をあちこちにばら撒いておいたんです。","ENG":"Yes. We've scattered freshly mined Eternium ores from the Counterside here and there.","TWN":"沒錯，我把剛從異界開採來的新鮮永恆之金原石散布在這附近。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"그, 그런 짓을 해도 되나요?!","JPN":"そ、そんなことして大丈夫なんですか？","ENG":"I-is it okay to do that?","TWN":"真、真的可以這樣做嗎？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"물론이죠. 우리 폴른 호크 탐정 사무소는 고객 만족을 위해서라면 무슨 일이든지 OK입니다.","JPN":"もちろんです。私たち、フォーレン・ホーク探偵事務所は、顧客満足を高めるためならなんでもOKです。","ENG":"Sure, why not? We at Fallen Hawk Private Eye can do anything to satisfy our customers.","TWN":"當然，我們墮落之鷹偵探事務所為了顧客滿意度，做什麼都是OK的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크히힛, 간만에 신나게 놀아볼까?","JPN":"ククッ、久々に暴れようか。","ENG":"Teehee, I can't wait to have fun after so long!","TWN":"嘿嘿，好久沒有痛快地大玩一番啦！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그보다 너무 망가트리면 안 된단다. 내 동생. 그래선 제물로서 성립이 안 되니까.","JPN":"それより、あんまり壊しちゃだめだ。私の妹よ。供え物として成立しないからな。","ENG":"Don't damage them too much, my little sister. We need them as offerings.","TWN":"不能弄壞喔，妹妹。弄壞了就不能當作祭品使用了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L30_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"알고 있어! 살살 밟도록 노력해볼게.","JPN":"わかってるよ！　そっと握りつぶすよう努力してみる！","ENG":"I know! I'll try not to crush them too hard.","TWN":"知道啦！我會儘可能溫柔地踩下去的。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L32_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"으응......???","JPN":"ううん……？？？","ENG":"Erm?","TWN":"咦……？？？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};